import{WithParams}from"./WithParams.js";class Osc extends WithParams{constructor(){super(),this.oscNode=this.context().createOscillator(),this.gainNode=this.context().createGain(),this.oscNode.connect(this.gainNode),this.oscNode.type=this.type,this.conversions.beats=value=>this.beatsToHertz(value),this.mirrorParams({gain:this.gainNode.gain,beats:this.oscNode.frequency,detune:this.oscNode.detune,type:this.oscNode})}start(time){this.oscNode.start(time)}stop(time){this.oscNode.stop(time)}get type(){let value=this.getAttribute("type");return["square","sawtooth","triangle"].find(v=>v===value)||"sine"}set type(value){this.setAttribute("type",value)}get gain(){let value=this.getAttribute("gain");return value?parseFloat(value):1}set gain(value){this.setAttribute("gain",value)}get detune(){let value=this.getAttribute("detune");return value?parseFloat(value):1}set detune(value){this.setAttribute("detune",value)}get beats(){let value=parseFloat(this.getAttribute("beats"));return this.invert?-1*value:value}set beats(value){this.setAttribute("beats",value)}get invert(){return this.hasAttribute("invert")}set invert(value){this.toBoolean("invert",value)}static get observedAttributes(){return["beats","gain","detune","type"]}}export{Osc};